import{_ as e,o as a,c as s,ag as i}from"./chunks/framework.6ZJjlmu_.js";const u=JSON.parse('{"title":"IL patterns and limitations","description":"","frontmatter":{},"headers":[],"relativePath":"reference/il-limitations.md","filePath":"reference/il-limitations.md"}'),n={name:"reference/il-limitations.md"};function o(r,t,l,d,c,h){return a(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="il-patterns-and-limitations" tabindex="-1">IL patterns and limitations <a class="header-anchor" href="#il-patterns-and-limitations" aria-label="Permalink to &quot;IL patterns and limitations&quot;">​</a></h1><p>Event Monitor’s <strong>INVOKE</strong> instrumentation is <strong>pattern-based</strong>. Typical C# event usage works well; indirection does not.</p><h2 id="support-matrix" tabindex="-1">Support matrix <a class="header-anchor" href="#support-matrix" aria-label="Permalink to &quot;Support matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>Supported</th><th>Notes</th></tr></thead><tbody><tr><td><code>MyEvent?.Invoke(args)</code></td><td>Usually yes</td><td>Recommended default style</td></tr><tr><td>Local copy + <code>Invoke</code></td><td>Usually yes</td><td>Fallback style for edge IL cases</td></tr><tr><td>Custom dispatcher helper</td><td>Maybe</td><td>Depends on emitted IL shape</td></tr><tr><td>Reflection (<code>DynamicInvoke</code>)</td><td>Usually no</td><td>Not a direct event invoke pattern</td></tr><tr><td>Obfuscated/generated unusual IL</td><td>Maybe</td><td>Verify with ILPP diagnostics</td></tr></tbody></table><h2 id="patterns-that-usually-work" tabindex="-1">Patterns that usually work <a class="header-anchor" href="#patterns-that-usually-work" aria-label="Permalink to &quot;Patterns that usually work&quot;">​</a></h2><ul><li><code>MyEvent?.Invoke(...)</code></li><li>Copy to a local, then invoke, for example:</li></ul><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> h</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> MyEvent;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (h </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    h.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Invoke</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.);</span></span></code></pre></div><h2 id="patterns-that-may-not-be-tracked" tabindex="-1">Patterns that may not be tracked <a class="header-anchor" href="#patterns-that-may-not-be-tracked" aria-label="Permalink to &quot;Patterns that may not be tracked&quot;">​</a></h2><ul><li>Invocation through a <strong>custom dispatcher</strong> that does not expose a direct <code>Invoke</code> call matching the injector’s rules.</li><li><strong>Reflection-based</strong> <code>Delegate.DynamicInvoke</code> or similar.</li><li><strong>Non-standard</strong> IL produced by source generators or obfuscators (case-by-case).</li></ul><p>If a fire is missing, confirm with <a href="./../how-to/ilpp-diagnostics.html">ILPP diagnostics</a> and consider restructuring the hot path or using <code>TagPayload</code> + manual <code>RecordInvoke</code> only for diagnostics.</p><h2 id="custom-event-accessors" tabindex="-1">Custom event accessors <a class="header-anchor" href="#custom-event-accessors" aria-label="Permalink to &quot;Custom event accessors&quot;">​</a></h2><p>Standard <strong>field-like events</strong> are straightforward. <strong>Custom</strong> <code>add</code> / <code>remove</code> accessors with unusual backing storage may require heuristic resolution; edge cases are possible.</p><h2 id="static-events" tabindex="-1">Static events <a class="header-anchor" href="#static-events" aria-label="Permalink to &quot;Static events&quot;">​</a></h2><p>Static events are tracked with <strong><code>instanceId = 0</code></strong>. You still distinguish by <strong>owner type + event name</strong>, not by a specific object instance.</p><h2 id="assembly-coverage" tabindex="-1">Assembly coverage <a class="header-anchor" href="#assembly-coverage" aria-label="Permalink to &quot;Assembly coverage&quot;">​</a></h2><p>Only assemblies the post-processor <strong>includes</strong> are rewritten. Unity, system, and Event Monitor internal assemblies are skipped. Your gameplay code should live in <strong>user</strong> assemblies (for example <code>Assembly-CSharp</code> or your asmdefs).</p><h2 id="payload-capture" tabindex="-1">Payload capture <a class="header-anchor" href="#payload-capture" aria-label="Permalink to &quot;Payload capture&quot;">​</a></h2><p>When <strong>Payload</strong> is off, INVOKE rows intentionally omit arguments. When on, arguments are captured for <strong>instrumented</strong> sites; otherwise use <code>TagPayload</code> before firing.</p><h2 id="unity-c-compatibility" tabindex="-1">Unity / C# compatibility <a class="header-anchor" href="#unity-c-compatibility" aria-label="Permalink to &quot;Unity / C# compatibility&quot;">​</a></h2><p>Some Unity versions have edge cases with <strong>lambda</strong> subscriptions (<code>event += _ =&gt; ...</code>). Prefer <strong>named methods</strong> for maximum compatibility when subscribing and unsubscribing.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../concepts/ilpp-vs-reflection-scanner.html">ILPP vs ReflectionScanner</a></li><li><a href="./../troubleshooting/faq.html">Troubleshooting &amp; FAQ</a></li></ul>`,22)])])}const m=e(n,[["render",o]]);export{u as __pageData,m as default};
